function(sid, uid, cartCount, viewedProducts, articleTypes, lastTs){
  var cart = (typeof cartCount === 'number') ? cartCount : 0;
  if (cart > 0) return [];

  var prods = (Array.isArray(viewedProducts) ? viewedProducts : []).filter(function(x){ return x != null && x !== ''; });
  var distinct = prods.length;
  if (distinct < 3) return [];

  var severity;
  if (distinct >= 7) severity = 'high';
  else if (distinct >= 5) severity = 'medium';
  else severity = 'low';

  var counts = Object.create(null);
  var topAT = null; var topN = 0;
  var ats = Array.isArray(articleTypes) ? articleTypes : [];
  for (var i = 0; i < ats.length; i++){
    var a = ats[i];
    if (a == null || a === '') continue;
    a = String(a);
    counts[a] = (counts[a] || 0) + 1;
    if (counts[a] > topN){ topN = counts[a]; topAT = a; }
  }

  var evidence;
  if (severity === 'high') evidence = 'Explored many products (' + distinct + ') in the last 30 seconds with no add-to-cart, suggesting scattered attention and difficulty converging.';
  else if (severity === 'medium') evidence = 'Explored several products (' + distinct + ') in the last 30 seconds with no add-to-cart, suggesting choice overload.';
  else evidence = 'Explored a few products (' + distinct + ') in the last 30 seconds with no add-to-cart, suggesting early search friction.';

  var t = lastTs ? new Date(lastTs) : new Date();
  var bucket = Math.floor(t.getTime() / 30000);

  var doc = { _id: String(sid) + ':searchfriction:' + bucket, sid: sid, uid: uid, signal: 'search-friction', severity: severity, distinctProducts: distinct, evidence: evidence, _tsFallback: t };
  if (topAT) doc.topic = { dimension: 'articleType', value: topAT };
  return [doc];
}
